const message = $input.first().json.chatInput || '';
const sessionId = $input.first().json.sessionId || 'anonymous';

return [{
  json: {
    user_id: sessionId,
    message: message.trim(),
    timestamp: new Date().toISOString()
  }
}];

const userData = $('Check User & Route').first().json;
const message = userData.message;
const userId = userData.user_id;

// Get last 5 messages for context
const history = $input.all().slice(-5);

let conversationHistory = '';
history.forEach(h => {
  const userMsg = h.json.user_message;
  const botMsg = h.json.bot_response;
  // Only include rows that have actual content
  if (userMsg && botMsg && userMsg !== 'undefined' && botMsg !== 'undefined') {
    conversationHistory += `User: ${userMsg}\nCoach: ${botMsg}\n\n`;
  }
});

// Detect intent
const intentKeywords = {
  salary: ['salary', 'raise', 'pay', 'negotiate', 'compensation', 'money', 'increment'],
  interview: ['interview', 'job', 'hired', 'application', 'resume', 'cv', 'hiring'],
  career_change: ['change', 'pivot', 'switch', 'new career', 'different field', 'quit'],
  leadership: ['leadership', 'boss', 'manager', 'team', 'assertive', 'authority', 'speak up'],
  confidence: ['confidence', 'scared', 'nervous', 'afraid', 'doubt', 'imposter', 'worthy'],
  balance: ['balance', 'burnout', 'stress', 'overwhelm', 'tired', 'boundaries', 'overworked']
};

let detectedIntent = 'general';
const msgLower = message.toLowerCase();

for (const [intent, keywords] of Object.entries(intentKeywords)) {
  if (keywords.some(k => msgLower.includes(k))) {
    detectedIntent = intent;
    break;
  }
}

// Topic specific system prompts
const systemPrompts = {
  salary: `You are an expert salary negotiation coach for women. You help women confidently negotiate raises and compensation. Be specific, tactical, and encouraging. Give exact scripts and phrases they can use.`,
  interview: `You are an expert interview coach for women. You help women prepare for job interviews, craft compelling answers, and present themselves confidently. Give specific tips and practice questions.`,
  career_change: `You are an expert career transition coach for women. You help women navigate career pivots with clarity and confidence. Be practical about steps, timelines, and skill gaps.`,
  leadership: `You are an expert leadership coach for women. You help women develop their leadership presence, handle difficult workplace dynamics, and build authority. Be direct and empowering.`,
  confidence: `You are an expert confidence coach for women. You help women overcome imposter syndrome, self-doubt, and fear. Be warm, encouraging, and give concrete mindset tools.`,
  balance: `You are an expert work-life balance coach for women. You help women set boundaries, manage burnout, and create sustainable careers. Be compassionate and practical.`,
  general: `You are an expert career coach for women. You help women grow their careers, build confidence, and achieve their professional goals. Be encouraging, practical, and specific.`
};

const prompt = `${systemPrompts[detectedIntent]}

User Profile:
- Name: ${userData.name}
- Career Stage: ${userData.career_stage}
- Biggest Challenge: ${userData.challenge}
- This Month's Goal: ${userData.goal}

Recent Conversation:
${conversationHistory || 'This is the first coaching message.'}

User's Message: ${message}

Respond in this JSON format:
{
  "main_advice": "2-3 paragraph personalized coaching response",
  "actionable_step": "One specific action they can take today",
  "follow_up_question": "One question to keep them moving forward",
  "intent_detected": "${detectedIntent}"
}

Rules:
- Always address them by name
- Reference their specific goal and challenge
- Be direct and confident not vague
- Give real tactical advice not generic tips
- End with the follow up question to continue the conversation`;

return [{
  json: {
    ...userData,
    prompt,
    intent: detectedIntent
  }
}];

const response = items[0].json.output[0].content[0].text;
const cleaned = response.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

const userData = $('Check User & Route').first().json;

const formattedResponse = `${parsed.main_advice}\n\n✅ *Your Action for Today:*\n${parsed.actionable_step}\n\n💭 ${parsed.follow_up_question}`;

return [{
  json: {
    ...userData,
    coaching_response: formattedResponse,
    main_advice: parsed.main_advice,
    actionable_step: parsed.actionable_step,
    follow_up_question: parsed.follow_up_question,
    intent: parsed.intent_detected
  }
}];

const response = items[0].json.output[0].content[0].text;
const cleaned = response.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

const userData = $('Build Checkin Prompt').item.json;

const emailBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; background: #f9f4ff; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 30px auto; background: #ffffff; border-radius: 12px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.08); }
    .header { background: linear-gradient(135deg, #7b2ff7, #f107a3); padding: 30px; text-align: center; color: white; }
    .header h1 { margin: 0; font-size: 22px; }
    .body { padding: 30px; color: #333; }
    .challenge-box { background: #f3eaff; border-left: 4px solid #7b2ff7; padding: 16px 20px; border-radius: 8px; margin: 20px 0; }
    .quote-box { background: #fff0fb; border-left: 4px solid #f107a3; padding: 14px 18px; border-radius: 8px; margin: 20px 0; font-style: italic; }
    .footer { background: #f9f4ff; padding: 16px; text-align: center; font-size: 12px; color: #999; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>💜 Your Weekly Check-in</h1>
    </div>
    <div class="body">
      <p>${parsed.greeting}</p>
      <p>${parsed.progress_acknowledgment}</p>
      <div class="challenge-box">
        <strong>🎯 This Week's Challenge:</strong><br/><br/>
        ${parsed.weekly_challenge}
      </div>
      <div class="quote-box">
        💬 ${parsed.motivational_quote}
      </div>
      <p>${parsed.closing}</p>
    </div>
    <div class="footer">You're receiving this because you're part of the AI Confidence Coach community.<br/>Reply to this email anytime — we're here for you. 💜</div>
  </div>
</body>
</html>`;

return [{
  json: {
    ...userData,
    email_subject: parsed.subject,
    email_body: emailBody
  }
}];

const userId = $('Extract User & Message').first().json.user_id;
const message = $('Extract User & Message').first().json.message;

// Lookup maps for numbered responses
const careerStageMap = {
  '1': 'Student or Fresh Graduate',
  '2': 'Early Career (1-3 years)',
  '3': 'Mid Career (4-8 years)',
  '4': 'Senior or Leadership',
  '5': 'Career Changer'
};

const challengeMap = {
  '1': 'Salary negotiation',
  '2': 'Interview confidence',
  '3': 'Career change or pivot',
  '4': 'Leadership and assertiveness',
  '5': 'Work-life balance',
  '6': 'Building my network'
};

// Read all users from sheet
const allUsers = $input.all();

// Find this specific user
const existingUser = allUsers.find(u => String(u.json.user_id) === String(userId));

// Brand new user
if (!existingUser) {
  return [{
    json: {
      user_id: userId,
      message,
      onboarding_step: 0,
      is_new: true,
      name: '',
      career_stage: '',
      challenge: '',
      goal: '',
      response: `👋 Welcome to your AI Confidence Coach!\n\nI'm here to help you navigate salary negotiations, interview prep, career changes, and building unshakeable confidence at work.\n\nLet's start with a quick setup so I can give you the most relevant advice.\n\n*What's your name?*`
    }
  }];
}

const user = existingUser.json;
const step = Number(user.onboarding_step) || 0;

// Step 1 — Got name, ask career stage
if (step === 1) {
  return [{
    json: {
      user_id: userId,
      message,
      onboarding_step: 1,
      is_new: false,
      name: message,
      career_stage: '',
      challenge: user.challenge || '',
      goal: user.goal || '',
      response: `Nice to meet you, ${message}! 🌟\n\nWhat best describes your current career stage?\n\n1️⃣ Student or Fresh Graduate\n2️⃣ Early Career (1-3 years)\n3️⃣ Mid Career (4-8 years)\n4️⃣ Senior or Leadership\n5️⃣ Career Changer\n\nJust type the number or your answer.`
    }
  }];
}

// Step 2 — Got career stage, ask biggest challenge
if (step === 2) {
  return [{
    json: {
      user_id: userId,
      message,
      onboarding_step: 2,
      is_new: false,
      name: user.name || '',
      career_stage: careerStageMap[message.trim()] || message,
      challenge: '',
      goal: user.goal || '',
      response: `Got it! 💪\n\nWhat's your biggest challenge right now?\n\n1️⃣ Salary negotiation\n2️⃣ Interview confidence\n3️⃣ Career change or pivot\n4️⃣ Leadership and assertiveness\n5️⃣ Work-life balance\n6️⃣ Building my network\n\nType the number or describe it in your own words.`
    }
  }];
}

// Step 3 — Got challenge, ask goal
if (step === 3) {
  return [{
    json: {
      user_id: userId,
      message,
      onboarding_step: 3,
      is_new: false,
      name: user.name || '',
      career_stage: user.career_stage || '',
      challenge: challengeMap[message.trim()] || message,
      goal: '',
      response: `Love the honesty! 🙌\n\nLast question — what's your main goal for this month?\n\nFor example: "Get a raise", "Land a new job", "Feel more confident in meetings", "Start my own business"\n\nTell me in your own words.`
    }
  }];
}

// Step 4 — Onboarding complete
if (step === 4) {
  const careerLabel = user.career_stage || '';
  const challengeLabel = user.challenge || '';
  return [{
    json: {
      user_id: userId,
      message,
      onboarding_step: 4,
      is_new: false,
      is_complete: true,
      name: user.name || '',
      career_stage: careerLabel,
      challenge: challengeLabel,
      goal: message,
      response: `You're all set, ${user.name}! 🎉\n\nHere's what I know about you:\n📍 Career Stage: ${careerLabel}\n🎯 Biggest Challenge: ${challengeLabel}\n🌟 This Month's Goal: ${message}\n\nI'm ready to coach you. Ask me anything — salary negotiation, interview tips, how to handle a difficult boss, career pivots, or just a confidence boost when you need one.\n\n*What would you like help with today?*`
    }
  }];
}

// Step 5+ — Onboarding done, ready for coaching
return [{
  json: {
    user_id: userId,
    message,
    onboarding_step: step,
    is_new: false,
    is_onboarding_complete: true,
    name: user.name || '',
    career_stage: user.career_stage || '',
    challenge: user.challenge || '',
    goal: user.goal || '',
    response: null
  }
}];

const users = $('Filter Onboarded Users').all();
const convLog = $('Read Conversation Log').all();

return users.map(user => {
  const u = user.json;

  // Get last interaction for this user
  const userConvs = convLog
    .filter(c => String(c.json.user_id) === String(u.user_id))
    .slice(-3);

  let lastTopics = 'general career growth';
  if (userConvs.length > 0) {
    const intents = userConvs.map(c => c.json.intent).filter(Boolean);
    lastTopics = intents.length > 0 ? intents.join(', ') : 'general career growth';
  }

  const prompt = `You are a warm and inspiring women's career coach sending a weekly check-in message.

User Profile:
- Name: ${u.name}
- Career Stage: ${u.career_stage}
- Biggest Challenge: ${u.challenge}
- This Month's Goal: ${u.goal}
- Recent Topics Discussed: ${lastTopics}

Write a personalized weekly check-in message. Respond ONLY in this JSON format:
{
  "subject": "email subject line with their name",
  "greeting": "warm personalized opening",
  "progress_acknowledgment": "acknowledge their journey and what they've been working on",
  "weekly_challenge": "one specific challenge or task for this week related to their goal",
  "motivational_quote": "an inspiring quote from a woman leader relevant to their situation",
  "closing": "warm encouraging closing"
}

Rules:
- Use their name throughout
- Reference their specific goal and challenge
- Weekly challenge must be concrete and achievable in one week
- Keep the tone warm, sisterly, and empowering
- Quote must be from a real woman leader`;

  return {
    json: {
      user_id: u.user_id,
      name: u.name,
      email: u.email || '',
      career_stage: u.career_stage,
      challenge: u.challenge,
      goal: u.goal,
      last_topics: lastTopics,
      prompt
    }
  };
});
